def solve(deps):
    from collections import defaultdict

    all_tasks = set(deps.keys())
    for prereqs in deps.values():
        all_tasks.update(prereqs)

    graph = defaultdict(list)
    indegree = {task: 0 for task in all_tasks}

    for task, prereqs in deps.items():
        for pre in prereqs:
            graph[pre].append(task)
            indegree[task] += 1

    current_layer = sorted([t for t in all_tasks if indegree[t] == 0])
    result = []
    processed = 0

    while current_layer:
        result.append(current_layer)
        processed += len(current_layer)
        next_candidates = []
        for task in current_layer:
            for neighbor in graph[task]:
                indegree[neighbor] -= 1
                if indegree[neighbor] == 0:
                    next_candidates.append(neighbor)
        current_layer = sorted(next_candidates)

    return result if processed == len(all_tasks) else []
