from collections import OrderedDict

def solve(capacity: int, ops: list[str]) -> list[int]:
    if capacity == 0:
        return [-1 for op in ops if op.startswith("get")]

    cache = OrderedDict()
    result = []

    for op in ops:
        parts = op.split()
        if parts[0] == "get":
            key = int(parts[1])
            if key in cache:
                cache.move_to_end(key)
                result.append(cache[key])
            else:
                result.append(-1)
        else:  # put
            key = int(parts[1])
            value = int(parts[2])
            if key in cache:
                cache[key] = value
                cache.move_to_end(key)
            else:
                cache[key] = value
                if len(cache) > capacity:
                    cache.popitem(last=False)

    return result
