import heapq
from collections import Counter

def solve(nums: list[int], k: int) -> list[float]:
    small = []
    large = []
    small_removed = Counter()
    large_removed = Counter()

    def prune(heap, removed):
        while heap:
            val = -heap[0] if heap is small else heap[0]
            if removed[val] > 0:
                removed[val] -= 1
                if removed[val] == 0:
                    del removed[val]
                heapq.heappop(heap)
            else:
                break

    def balance():
        prune(small, small_removed)
        prune(large, large_removed)
        if len(small) > len(large) + 1:
            val = -heapq.heappop(small)
            heapq.heappush(large, val)
        elif len(small) < len(large):
            val = heapq.heappop(large)
            heapq.heappush(small, -val)
        prune(small, small_removed)
        prune(large, large_removed)

    def add(num):
        if not small or num <= -small[0]:
            heapq.heappush(small, -num)
        else:
            heapq.heappush(large, num)
        balance()

    def remove(num):
        prune(small, small_removed)
        prune(large, large_removed)
        if num <= -small[0]:
            small_removed[num] += 1
            if num == -small[0]:
                prune(small, small_removed)
        else:
            large_removed[num] += 1
            if large and num == large[0]:
                prune(large, large_removed)
        balance()

    for i in range(k):
        add(nums[i])

    res = []
    if k % 2 == 1:
        res.append(-small[0])
    else:
        res.append((-small[0] + large[0]) / 2.0)

    for i in range(k, len(nums)):
        remove(nums[i - k])
        add(nums[i])
        if k % 2 == 1:
            res.append(-small[0])
        else:
            res.append((-small[0] + large[0]) / 2.0)

    return res
